USE master;
GO

-- 若数据库已存在则删除重建
IF EXISTS (SELECT name FROM sys.databases WHERE name = N'MingDynastyDB')
BEGIN
    ALTER DATABASE MingDynastyDB SET SINGLE_USER WITH ROLLBACK IMMEDIATE;
    DROP DATABASE MingDynastyDB;
END
GO

-- 创建数据库
CREATE DATABASE MingDynastyDB;
GO
USE MingDynastyDB;
GO


-- 管理员表
CREATE TABLE AdminUser(
    ID INT PRIMARY KEY IDENTITY(1,1),
    UserName NVARCHAR(50) NOT NULL UNIQUE,
    Pwd NVARCHAR(200) NOT NULL -- 存储PBKDF2哈希
);
GO

-- 普通用户表 
CREATE TABLE MingUser(
    ID INT PRIMARY KEY IDENTITY(1,1),
    UserName NVARCHAR(50) NOT NULL UNIQUE,
    NickName NVARCHAR(50),
    Pwd NVARCHAR(200) NOT NULL, --  存储PBKDF2哈希
    Email NVARCHAR(100),
    Avatar NVARCHAR(200),
    RegisterTime DATETIME DEFAULT GETDATE(),
    LastLoginTime DATETIME,
    Status BIT DEFAULT 1
);
GO

-- 明朝皇帝表 
CREATE TABLE MingEmperor(
    ID INT PRIMARY KEY IDENTITY(1,1),
    EmpName NVARCHAR(50) NOT NULL,
    ReignTitle NVARCHAR(30),
    TempleName NVARCHAR(30),
    ReignYears NVARCHAR(50),
    Intro NVARCHAR(MAX),
    Period NVARCHAR(20),
    Sort INT DEFAULT 0,
    Avatar NVARCHAR(200)
);
GO

-- 历史事件表（外键关联皇帝）
CREATE TABLE MingEvent(
    ID INT PRIMARY KEY IDENTITY(1,1),
    EventName NVARCHAR(100) NOT NULL,
    EventYear INT,
    EmpID INT,
    Content NVARCHAR(MAX),
    Period NVARCHAR(20),
    Sort INT DEFAULT 0,
    FOREIGN KEY (EmpID) REFERENCES MingEmperor(ID)
);
GO

-- 典章制度文章表
CREATE TABLE MingSystemArticle(
    ID INT PRIMARY KEY IDENTITY(1,1),
    Title NVARCHAR(200) NOT NULL,
    Category NVARCHAR(50),
    Content NVARCHAR(MAX),
    IsTop BIT DEFAULT 0,
    IsShow BIT DEFAULT 1,
    CreateTime DATETIME DEFAULT GETDATE()
);
GO

-- 名臣名将表
CREATE TABLE MingFigure(
    ID INT PRIMARY KEY IDENTITY(1,1),
    Name NVARCHAR(50) NOT NULL,
    Category NVARCHAR(20),
    BirthYear INT,
    DeathYear INT,
    IdentityTitle NVARCHAR(100),
    Achievement NVARCHAR(200),
    Avatar NVARCHAR(200),
    Intro NVARCHAR(MAX),
    Sort INT DEFAULT 0
);
GO

-- 文化科技表
CREATE TABLE MingCulture(
    ID INT PRIMARY KEY IDENTITY(1,1),
    Title NVARCHAR(200) NOT NULL,
    Category NVARCHAR(50),
    Author NVARCHAR(50),
    Cover NVARCHAR(200),
    Content NVARCHAR(MAX),
    Sort INT DEFAULT 0,
    CreateTime DATETIME DEFAULT GETDATE()
);
GO

-- 轮播图表
CREATE TABLE MingBanner(
    ID INT PRIMARY KEY IDENTITY(1,1),
    Title NVARCHAR(100),
    ImageUrl NVARCHAR(200),
    LinkUrl NVARCHAR(200),
    Sort INT DEFAULT 0
);
GO
      

-- 留言板表（外键关联用户）
CREATE TABLE MingMessage(
    ID INT PRIMARY KEY IDENTITY(1,1),
    UserID INT NULL,
    NickName NVARCHAR(50),
    Content NVARCHAR(500) NOT NULL,
    ReplyContent NVARCHAR(500),
    IsTop BIT DEFAULT 0,
    IsAnonymous BIT DEFAULT 1,
    CreateTime DATETIME DEFAULT GETDATE(),
    ReplyTime DATETIME NULL,
    FOREIGN KEY (UserID) REFERENCES MingUser(ID)
);
GO


