-- 16位皇帝
SET IDENTITY_INSERT MingEmperor ON;
GO
INSERT INTO MingEmperor (ID, EmpName, ReignTitle, TempleName, ReignYears, Intro, Period, Sort, Avatar)
VALUES
(1,N'朱元璋',N'洪武',N'明太祖',N'1368-1398',N'明朝开国皇帝，庙号太祖，谥号高皇帝。出身濠州钟离贫苦农家，原名朱重八，少年时遭遇濠州大旱、蝗灾与瘟疫，父母兄长半月内相继离世，无地安葬，只得入皇觉寺为僧。后因寺庙饥荒，云游淮西三年，饱尝民间疾苦，也见识了元末乱世的动荡。元至正十二年，投奔濠州红巾军郭子兴部，因作战勇猛、谋略过人得到赏识，娶郭子兴养女马氏为妻。郭子兴死后，他逐渐接管其部众，采纳朱升“高筑墙、广积粮、缓称王”的战略，先后击败陈友谅、张士诚等割据势力，统一江南。1368年正月初四，在应天府（今南京）称帝，国号大明，年号洪武。同年命徐达、常遇春北伐，攻克元大都，结束了蒙古在中原97年的统治。在位三十一年，推行一系列休养生息与加强皇权的政策：政治上废除丞相与中书省，设三司分掌地方权力，六部直接对皇帝负责，制定《大明律》与《大诰》，严惩贪官污吏，郭桓案、空印案牵连数万人；经济上移民垦荒、兴修水利、轻徭薄赋，全国耕地面积从元末的不足2亿亩增至8.5亿亩，人口恢复至6000万以上；军事上创立卫所制度，军屯自给，分封诸子为藩王镇守边疆。他开创的“洪武之治”为明朝近三百年基业奠定了坚实基础，但晚年为巩固皇权，大肆诛杀开国功臣，蓝玉案、胡惟庸案株连数万人，留下了皇权过度集中的隐患。洪武三十一年病逝，享年71岁，因太子朱标早逝，传位皇太孙朱允炆。',N'初期',1,N'~/upload/emperor_01.jpg'),
(2,N'朱允炆',N'建文',N'明惠宗',N'1398-1402',N'明太祖朱元璋之孙，懿文太子朱标次子，因长兄早逝被立为皇太孙。自幼聪慧好学，性情仁厚，深受儒家思想影响，与朱元璋的严苛治国风格截然不同。洪武三十一年即位，改元建文，史称建文帝。即位后立即推行“建文新政”：政治上提高文官地位，放宽刑罚，平反洪武年间的冤假错案；经济上减免江南地区过重的赋税，尤其是苏松地区的重赋，减轻百姓负担；同时为解决藩王拥兵自重的问题，在齐泰、黄子澄、方孝孺等文臣的建议下大力削藩。短短一年间，先后削夺周、齐、湘、代、岷五位藩王的爵位，湘王朱柏自焚而死，其余皆被废为庶人。建文元年七月，燕王朱棣以“清君侧、诛齐黄”为名，在北平起兵反抗，史称“靖难之役”。战争初期，朝廷拥有全国资源与数十万大军，占据绝对优势，但建文帝性格优柔寡断，指挥失当，又下达“勿伤吾叔”的荒唐命令，加之朱元璋晚年诛杀功臣导致将才匮乏，朝廷军屡战屡败。建文四年六月，朱棣绕过朝廷重兵，率轻骑直取南京。谷王朱橞与李景隆打开金川门投降，南京城破，皇宫燃起大火，建文帝下落不明，成为明朝第一大悬案。有说他自焚而死，有说他出家为僧云游四方，还有说他流亡海外。清乾隆年间追谥为“恭闵惠皇帝”，后世多称明惠宗。',N'初期',2,N'~/upload/emperor_02.jpg'),
(3,N'朱棣',N'永乐',N'明成祖',N'1402-1424',N'明太祖第四子，洪武三年被封为燕王，就藩北平。他自幼习武，精通兵法，多次率军北征蒙古，战功赫赫，在北方军队中威望极高。建文元年发动靖难之役，历时四年夺取皇位，改元永乐，史称明成祖。在位二十二年，是明朝最具雄才大略的皇帝之一。军事上五次亲征漠北，斡难河之战大败本雅失里，忽兰忽失温之战重创瓦剌三部，使蒙古势力长期不敢南犯；设立奴儿干都司，管辖黑龙江、乌苏里江流域的广大地区；征服安南，设立交阯布政使司，将越南重新纳入中国版图。政治上正式设立内阁制度，选拔解缙、杨荣等七人入直文渊阁参与机务，成为后世内阁制度的雏形；迁都北京，大规模营建紫禁城、天坛、太庙等皇家建筑，实现“天子守国门”的战略格局；疏通大运河会通河段，解决南北漕运问题，促进了南北经济文化交流。文化上命解缙、姚广孝等编纂《永乐大典》，汇集先秦至明初各类典籍八千余种，总字数约3.7亿字，是中国古代规模最大的类书；外交上派遣郑和率领庞大船队七下西洋，先后到达三十多个国家和地区，最远抵达东非沿岸，宣扬国威，建立了广泛的朝贡体系。他统治的时期，明朝国力强盛，疆域辽阔，史称“永乐盛世”。但连年征战与大规模工程也耗费了大量国力，百姓负担沉重。永乐二十二年，在第五次北征回师途中病逝于榆木川，享年65岁。',N'初期',3,N'~/upload/emperor_03.jpg'),
(4,N'朱高炽',N'洪熙',N'明仁宗',N'1424-1425',N'明成祖朱棣长子，洪武二十八年被立为燕王世子。他体态肥胖，行动不便，不善骑射，不受朱棣喜爱，但性格端重沉静，仁厚贤明，深得文臣拥戴。靖难之役中，他留守北平，以一万兵力成功抵御李景隆五十万大军的围攻，保住了朱棣的后方根据地，为靖难之役的胜利立下大功。永乐二年被立为皇太子，此后多次在朱棣北征期间监国，处理日常政务，积累了丰富的治国经验。但他的太子之位并不稳固，弟弟朱高煦、朱高燧多次图谋夺嫡，幸得杨士奇、杨荣等大臣的保护才得以保全。永乐二十二年即位，改元洪熙。即位后立即推行一系列缓和政策：停止下西洋、罢宝船建造，停止安南战事，节省巨额财政开支；平反建文旧臣冤案，释放方孝孺、解缙等被株连的家属；减免灾区赋税，调整苏松地区的重赋政策，鼓励农业生产；重用杨士奇、杨荣、杨溥等贤臣，整顿吏治，精简机构。他的统治虽然短暂，但纠正了永乐时期的诸多弊政，使百姓得以休养生息，为“仁宣之治”拉开了序幕。洪熙元年五月，在位仅十个月便病逝，享年48岁。临终前仍下诏要求丧事从简，不要劳民伤财，体现了他一贯的仁厚作风。',N'初期',4,N'~/upload/emperor_04.jpg'),
(5,N'朱瞻基',N'宣德',N'明宣宗',N'1425-1435',N'明仁宗朱高炽长子，自幼聪慧过人，深得祖父朱棣喜爱，永乐九年被立为皇太孙，多次跟随朱棣北征蒙古，学习军事与治国之道。洪熙元年即位，改元宣德。即位之初，汉王朱高煦效仿朱棣发动叛乱，朱瞻基御驾亲征，迅速平定乐安，生擒朱高煦，稳定了政局。此后他延续仁宗的休养生息政策，重用“三杨”、周忱、况钟等贤臣，整顿吏治，严惩贪官污吏；推行“一条鞭法”的雏形，简化赋役制度；兴修水利，治理黄河、淮河，农业生产得到快速发展。他统治的十年间，明朝政治清明，经济繁荣，百姓安居乐业，史称“仁宣之治”，被誉为明朝的“黄金时代”。文化上，他雅好丹青，擅长山水、花鸟、人物画，推动了明代宫廷艺术的繁荣，宣德炉、成化斗彩瓷器皆为此时的艺术珍品。但他也为明朝留下了隐患：为了提高行政效率，他设立内书堂，教宦官读书识字，开启了宦官参政的先例；放弃交阯布政使司，使明朝失去了对越南的控制；削减卫所兵力，导致军屯制度逐渐败坏。宣德十年病逝，享年38岁。',N'初期',5,N'~/upload/emperor_05.jpg'),
(6,N'朱祁镇',N'正统/天顺',N'明英宗',N'1435-1464',N'明宣宗朱瞻基长子，九岁即位，改元正统。初期由太皇太后张氏与“三杨”（杨士奇、杨荣、杨溥）辅政，延续仁宣旧政，政治清明，史称“正统初政”。但随着太皇太后与三杨相继去世，他逐渐宠信宦官王振，王振把持朝政，结党营私，打击异己，明朝政治开始走向腐败。正统十四年，蒙古瓦剌部首领也先以朝贡贸易纠纷为借口，兵分四路大举南犯。王振怂恿朱祁镇御驾亲征，朱祁镇不顾群臣反对，率领二十余万大军仓促出发。由于指挥混乱、粮草不济，大军在土木堡被瓦剌骑兵包围，明军全军覆没，随行文武大臣五十余人战死，朱祁镇本人被俘，史称“土木堡之变”。瓦剌挟持朱祁镇进攻北京，兵部尚书于谦拥立朱祁钰为帝，组织北京保卫战，击退瓦剌。一年后，朱祁镇被放回北京，被朱祁钰幽居南宫七年。景泰八年，朱祁钰病重，石亨、徐有贞、曹吉祥发动“夺门之变”，朱祁镇复辟，改元天顺。复辟后，他诛杀于谦等功臣，为王振平反，但也废除了明朝延续百年的妃嫔殉葬制度，这是他一生最大的善举。天顺八年病逝，享年38岁。他的一生充满戏剧性，是明朝唯一一位两次登基、做过俘虏的皇帝。',N'中期',6,N'~/upload/emperor_06.jpg'),
(7,N'朱祁钰',N'景泰',N'明代宗',N'1449-1457',N'明宣宗朱瞻基次子，明英宗朱祁镇异母弟，正统十四年被封为郕王。土木堡之变后，京师震动，人心惶惶，徐有贞等大臣主张南迁避祸，于谦力排众议，主张坚守北京。朱祁钰被拥立为监国，不久即位为帝，改元景泰，遥尊朱祁镇为太上皇。即位后，他重用于谦、王直等贤臣，迅速调集各地勤王军，整顿军备，在北京保卫战中大败瓦剌，使明朝转危为安。此后他整顿边防，加强京师防御，与瓦剌议和，迎回朱祁镇；整顿吏治，精简机构，减免赋税，治理黄河水患，使明朝的国力逐渐恢复。但他的皇位并不稳固，始终担心朱祁镇复辟。景泰三年，他废黜朱祁镇之子朱见深的太子之位，立自己的儿子朱见济为太子，不料朱见济次年夭折，储位空虚。景泰八年，朱祁钰病重，石亨、徐有贞等人发动夺门之变，朱祁镇复辟。朱祁钰被废为郕王，软禁于西苑，不久去世，享年30岁。朱祁镇赐谥号“戾”，以亲王礼葬于北京西山，是明朝唯一一位未被葬入十三陵的皇帝。直到南明弘光年间，才被追尊为代宗，谥号“符天建道恭仁康定隆文布武显德崇孝景皇帝”。',N'中期',7,N'~/upload/emperor_07.jpg'),
(8,N'朱见深',N'成化',N'明宪宗',N'1464-1487',N'明英宗朱祁镇长子，初名朱见濬。土木堡之变后被立为太子，景泰三年被朱祁钰废为沂王，天顺元年朱祁镇复辟后复立为太子，改名朱见深。幼年的坎坷经历使他性格懦弱，缺乏安全感，对从小照顾他的宫女万贞儿产生了深深的依赖。天顺八年即位，改元成化。即位之初，他平反于谦冤狱，恢复朱祁钰的帝号，任用李贤、彭时等贤臣，政治较为清明。但后来他逐渐沉迷后宫，专宠比自己大17岁的万贵妃，万贵妃把持后宫，迫害妃嫔皇子，导致他晚年才知有子朱祐樘。成化十三年，他设立西厂，由太监汪直统领。西厂权力远超东厂与锦衣卫，四处侦查，屡兴大狱，官员人人自危，朝政日益腐败。汪直倒台后，西厂虽被撤销，但宦官专权的局面并未改变。不过成化一朝也有一定的武功：成化三年，派大军平定广西大藤峡瑶民起义；成化十五年，派汪直率军征讨建州女真，史称“成化犁庭”，沉重打击了女真势力，稳定了东北边境。文化上，成化年间的瓷器工艺达到顶峰，尤其是成化斗彩鸡缸杯，被誉为瓷器中的珍品。成化二十三年病逝，享年41岁。',N'中期',8,N'~/upload/emperor_08.jpg'),
(9,N'朱祐樘',N'弘治',N'明孝宗',N'1487-1505',N'明宪宗朱见深第三子，生母纪氏是广西土官之女，因平定大藤峡起义被俘入宫。当时万贵妃专宠，迫害后宫妃嫔，纪氏怀孕后被打入冷宫，在冷宫中偷偷生下朱祐樘，由太监张敏与废后吴氏秘密抚养，直到六岁才与宪宗相认，被立为太子。成化二十三年即位，改元弘治。即位后，他驱逐万安、刘吉等奸佞，任用王恕、刘大夏、戴珊等贤臣，形成了“弘治朝多君子”的局面；勤于政事，每天早朝必到，还恢复了午朝，与大臣讨论政务；力行节俭，减少宫廷开支，禁止铺张浪费；多次减免灾区赋税，兴修水利，治理黄河、淮河，使农业生产得到恢复和发展。他为人宽厚仁慈，一生只娶张皇后一人，不纳妃嫔，是中国历史上唯一一位实践一夫一妻制的皇帝。他统治的十八年间，明朝政治清明，经济繁荣，百姓安居乐业，史称“弘治中兴”，被后世誉为“守成之君的典范”。但他也过于宽厚，对皇亲国戚的不法行为多有纵容，导致土地兼并日益严重。弘治十八年病逝，享年36岁。临终前，他嘱咐大臣要好好辅佐太子朱厚照，可惜朱厚照并未继承他的优良品质。',N'中期',9,N'~/upload/emperor_09.jpg'),
(10,N'朱厚照',N'正德',N'明武宗',N'1505-1521',N'明孝宗朱祐樘独子，自幼聪颖好动，喜欢骑射，深受孝宗宠爱。弘治十八年即位，改元正德。即位后，他厌倦枯燥的宫廷生活，宠信以刘瑾为首的“八虎”宦官，在西苑建造“豹房”，终日与宦官、美女、猛兽嬉戏，甚至在豹房处理政务，荒废朝政。刘瑾专权期间，结党营私，贪污受贿，打击异己，朝政极度腐败。正德五年，刘瑾谋反事发，朱厚照将其凌迟处死，但他并未因此醒悟，依旧沉迷游乐。他喜欢微服私访，多次偷偷溜出皇宫，到民间游玩；还自封“总督军务威武大将军总兵官”，改名朱寿，率军出征。正德十二年，蒙古鞑靼小王子率军南犯，朱厚照御驾亲征，在应州与蒙古军展开激战，亲自斩杀一人，大败蒙古军，史称“应州大捷”，使蒙古势力多年不敢南犯。正德十四年，宁王朱宸濠在南昌发动叛乱，朱厚照以平叛为名南巡，途中王阳明已平定叛乱，但他仍继续南巡，在清江浦捕鱼时落水染病。正德十六年，朱厚照病逝于豹房，享年31岁，无子嗣。他的一生充满争议，有人认为他荒淫无道，是昏君的代表；也有人认为他追求个性解放，聪明勇敢，只是不适合做皇帝。',N'中期',10,N'~/upload/emperor_10.jpg'),
(11,N'朱厚熜',N'嘉靖',N'明世宗',N'1521-1567',N'明宪宗朱见深之孙，兴献王朱祐杬次子，因明武宗朱厚照无子，以藩王身份入继大统，改元嘉靖。即位之初，他通过“大礼议”事件，与文官集团争论生父兴献王的尊号，左顺门事件中杖责百官一百三十四人，打死十七人，最终确立了自己的皇权。初期他整顿吏治，裁减冗员，减轻赋税，开放边贸，有所作为，史称“嘉靖新政”。但后来他逐渐沉迷道教，炼丹修道，追求长生不老，二十余年不上朝，不见大臣，将朝政交由严嵩、严世蕃父子处理。严嵩专权二十余年，贪污受贿，打击异己，朝政腐败，边防松弛。嘉靖年间，东南沿海倭寇猖獗，倭寇与中国海盗勾结，烧杀抢掠，无恶不作。在胡宗宪、戚继光、俞大猷等名将的努力下，经过多年征战，终于基本平定了倭患。嘉靖四十五年，户部主事海瑞上书批评世宗迷信道教、不理朝政、搜刮民脂民膏，称“嘉靖嘉靖，家家皆净”，世宗大怒，将海瑞下狱，但并未杀他。同年，世宗因长期服用丹药中毒身亡，享年60岁。他是明朝在位时间第二长的皇帝，统治前期有所作为，后期沉迷道教，导致明朝由盛转衰。',N'晚期',11,N'~/upload/emperor_11.jpg'),
(12,N'朱载坖',N'隆庆',N'明穆宗',N'1567-1572',N'明世宗朱厚熜第三子，因两个兄长早逝，被立为太子。早年作为裕王，不受世宗宠爱，生活简朴，深知民间疾苦。嘉靖四十五年即位，改元隆庆。即位后，他平反海瑞等因谏言获罪的官员，起用徐阶、高拱、张居正等贤臣；整顿吏治，裁减冗员，加强对官员的考核；开放边贸，与蒙古鞑靼部俺答汗达成“隆庆和议”，封俺答汗为顺义王，在大同、宣府等地设立互市，结束了明朝与蒙古长达两百年的敌对状态，此后北方边境数十年无大战。同时，他解除海禁，允许民间海外贸易，在福建漳州月港设立督饷馆，管理海外贸易，史称“隆庆开关”。隆庆开关后，大量中国的丝绸、瓷器、茶叶出口到海外，美洲的白银大量流入中国，促进了中国商品经济的发展。他性格宽厚，不喜欢独断专行，放手让大臣处理政务，形成了“阁臣相争”的局面，但也导致了党争的萌芽。隆庆六年，朱载坖病逝，享年36岁。他在位虽然只有六年，但纠正了嘉靖时期的诸多弊政，为张居正改革铺平了道路。',N'晚期',12,N'~/upload/emperor_12.jpg'),
(13,N'朱翊钧',N'万历',N'明神宗',N'1572-1620',N'明穆宗朱载坖第三子，十岁即位，改元万历。前十年由内阁首辅张居正主持政务，推行了一系列改革：政治上实行“考成法”，整顿吏治，提高行政效率；经济上清丈全国土地，推行“一条鞭法”，简化赋役制度，增加国家财政收入；军事上任用戚继光、李成梁等名将镇守边疆，巩固边防。张居正改革使明朝国力一度复兴，史称“万历中兴”。但张居正死后，万历帝亲政，为了报复张居正，下令抄没其家产，废除了大部分改革措施。此后，他因“国本之争”与文官集团矛盾激化，争立太子朱常洛与福王朱常洵，长达三十年不上朝，不见大臣，不批奏章，导致朝政瘫痪，官员空缺严重。万历年间，明朝进行了三次大规模的军事行动，史称“万历三大征”：宁夏之役平定哱拜叛乱，播州之役平定杨应龙叛乱，朝鲜之役援助朝鲜抗击日本丰臣秀吉的侵略。三大征虽然取得了胜利，但耗费了大量国力，使明朝财政陷入危机。与此同时，东北建州女真在努尔哈赤的带领下崛起，统一了女真各部。万历四十七年，明朝派四路大军进攻后金，在萨尔浒之战中大败而归，损失惨重，从此明朝在辽东由进攻转为防御。万历四十八年，朱翊钧病逝，享年58岁，是明朝在位时间最长的皇帝。他的统治是明朝由盛转衰的关键时期，后世多认为“明之亡，实亡于万历”。',N'晚期',13,N'~/upload/emperor_13.jpg'),
(14,N'朱常洛',N'泰昌',N'明光宗',N'1620-1620',N'明神宗朱翊钧长子，生母是宫女王氏。因神宗宠爱郑贵妃，想立郑贵妃之子福王朱常洵为太子，引发了长达三十年的“国本之争”。直到万历二十九年，朱常洛才被立为太子，但地位始终不稳，万历四十三年发生“梃击案”，有人持棍闯入太子东宫，意图刺杀朱常洛，事后不了了之。万历四十八年八月，朱常洛即位，改元泰昌。即位后，他推行了一系列改革措施：废除万历年间的矿税、榷税，减轻百姓负担；犒赏边防将士，补发拖欠的军饷；起用因谏言获罪的官员，整顿吏治。这些措施得到了朝野上下的一致好评，人们都期待他能成为一代明君。但朱常洛自幼体弱多病，即位后又沉溺女色，身体迅速垮掉。即位后第十天，他就一病不起。鸿胪寺丞李可灼进献“红丸”，朱常洛服用后病情稍有好转，又服用了第二颗，结果当天夜里就驾崩了，史称“红丸案”。朱常洛在位仅一个月，是明朝在位时间最短的皇帝。他的猝死引发了“移宫案”，李选侍占据乾清宫，企图挟持太子朱由校把持朝政，东林党人逼迫李选侍移宫，拥立朱由校即位。明末三大案（梃击案、红丸案、移宫案）至此齐备，加剧了明朝的政治混乱。',N'晚期',14,N'~/upload/emperor_14.jpg'),
(15,N'朱由校',N'天启',N'明熹宗',N'1620-1627',N'明光宗朱常洛长子，十六岁即位，改元天启。他自幼不受重视，没有接受过良好的教育，文化水平很低，被称为“文盲皇帝”。即位后，他不喜欢处理政务，将朝政交由乳母客氏与宦官魏忠贤处理。魏忠贤与客氏勾结，把持朝政，建立“阉党”，打击东林党人。天启五年，魏忠贤制造“六君子之狱”，逮捕杨涟、左光斗等六位东林党人，严刑拷打致死；天启六年，又制造“七君子之狱”，逮捕高攀龙、周顺昌等七位东林党人，高攀龙投水自尽，其余六人被折磨致死。阉党专权期间，朝政极度腐败，民不聊生。国内农民起义频发，天启七年，陕西发生大旱，王二率领饥民起义，揭开了明末农民大起义的序幕。辽东局势也岌岌可危，努尔哈赤攻占沈阳、辽阳，建立后金政权。虽然孙承宗、袁崇焕等名将在辽东修筑关宁锦防线，取得了宁远大捷、宁锦大捷，但难以挽回颓势。朱由校本人却是一位天才木匠，史载他“斧斤之属，皆躬自操之”，制作的家具、建筑模型精巧绝伦，甚至能亲自设计宫殿楼阁。天启七年，朱由校在西苑划船时落水染病，不久病逝，享年23岁，无子嗣，传位给弟弟朱由检。',N'晚期',15,N'~/upload/emperor_15.jpg'),
(16,N'朱由检',N'崇祯',N'明思宗',N'1627-1644',N'明光宗朱常洛第五子，明熹宗朱由校异母弟，天启七年即位，改元崇祯。即位后，他迅速铲除魏忠贤阉党，平反冤狱，起用东林党人；勤于政事，每天早起晚睡处理奏章，生活节俭，不近女色，试图挽救明朝的危局。但此时的明朝已经积重难返：内有李自成、张献忠等农民起义军不断壮大，建立大顺、大西政权，席卷全国；外有皇太极建立的清朝，多次入关劫掠，松锦之战明军主力全军覆没，洪承畴、祖大寿投降；加上明末小冰期，天灾不断，蝗灾、旱灾频发，百姓流离失所；朝廷财政枯竭，军饷拖欠严重，士兵哗变不断。崇祯帝性格多疑寡恩，刚愎自用，频繁更换内阁首辅，在位十七年更换了五十多位内阁大学士，诛杀了袁崇焕、孙传庭等多位能臣干将，导致人心惶惶，无人愿意为朝廷效力。崇祯十七年三月十九日，李自成率领大顺军攻破北京，崇祯帝逼死皇后周氏，斩杀长平公主，在太监王承恩的陪同下，自缢于煤山（今景山）的一棵歪脖树上，享年34岁。临死前，他在衣襟上写下“朕死，无面目见祖宗于地下，自去冠冕，以发覆面。任贼分裂朕尸，勿伤百姓一人”。明朝作为统一政权宣告灭亡，南明政权延续了近二十年。',N'晚期',16,N'~/upload/emperor_16.jpg');
GO
